input.command:
cd /home/user/rork-app && node -e "
const fs=require('fs'),path=require('path');
const dir='logs/audit/task-orchestrator';
const rows=[];
for (const d of fs.readdirSync(dir)) {
  const f=path.join(dir,d,'task.json');
  if (!fs.existsSync(f)) continue;
  try {
    const t=JSON.parse(fs.readFileSync(f,'utf8'));
    rows.push({id:d,title:(t.title||'').replace(/\s+/g,' ').slice(0,110),status:(t.status||'').toUpperCase(),created:t.createdAt||t.created_at||''});
  } catch(e){ rows.push({id:d,title:'PARSE_ERROR',status:'?',created:''}); }
}
rows.sort((a,b)=>(a.created||'').localeCompare(b.created||''));
rows.forEach((r,i)=>console.log((i+1)+'|'+(r.created||'?').slice(0,10)+'|'+r.status+'|'+r.title));
console.log('TOTAL='+rows.length);
const counts={};rows.forEach(r=>counts[r.status]=(counts[r.status]||0)+1);
console.log(JSON.stringify(counts));
"

